async signup(signupData: {
  email: string;
  name?: string;
  birthday?: Date | null;
}): Promise<MandatoryOrHavingError<'userId', string>> {
  // TODO: Use signupValidator.

  const { errors, result } = await this.wrapForApiError<{
    userId: string;
  }>(async () => {
    const payload = _.omitBy(
      {
        email: signupData.email,
        name: signupData.name,
        birthday: signupData.birthday
          ? format(signupData.birthday, 'yyyy-MM-dd')
          : null,
        inviteMode: 'link',
      },
      _.isUndefined,
    );

    return await this.client.post(`auth/signup`, payload);
  });

  return this.adjustApiResultForMandatoryObject(
    'userId',
    result?.userId ?? '',
    errors,
  );
}

